import threading
from concurrent.futures import ThreadPoolExecutor

def test_thread_safety(cache: LRUCache):
    def worker_read(key: str):
        try:
            return cache.get(key)
        except Exception as e:
            return str(e)

    def worker_write(key: str, value: str):
        cache.set(key, value, ttl=10)

    with ThreadPoolExecutor(max_workers=100) as executor:
        futures = []
        for i in range(50):
            futures.append(executor.submit(worker_read, f'key_{i}'))
            futures.append(executor.submit(worker_write, f'key_{i}', f'value_{i}'))
        results = [f.result() for f in futures]
```

